'use client';

import dynamic from 'next/dynamic';
import Link from 'next/link';
import { useCallback, useMemo, useState } from 'react';

import { useProductFormImages } from '@/features/products/context/ProductFormImageContext';
import { useProductSettings } from '@/features/products/hooks/useProductSettings';
import {
  buildQueuedProductFastCometUploadSource,
  markQueuedProductSource,
  removeQueuedProductSource,
} from '@/features/products/state/queued-product-ops';
import type { ImageFileSelection } from '@/shared/contracts/files';
import type {
  ProductImageManagerFastCometUploadErrorEvent,
  ProductImageManagerFastCometUploadEvent,
  ProductImageManagerFastCometUploadSuccessEvent,
} from '@/shared/contracts/product-image-manager';
import { Alert } from '@/shared/ui/primitives.public';
import { Button } from '@/shared/ui/button';
import { FormSection } from '@/shared/ui/form-section';
import { ProductImageManager, ProductImageManagerControllerProvider } from '@/shared/ui/image-slot-manager';
import type { ProductImageManagerController } from '@/shared/ui/image-slot-manager';
import { useToast } from '@/shared/ui/toast';

import {
  useOptionalProductImagesTabActionsContext,
  useOptionalProductImagesTabStateContext,
  type ProductImagesTabActionsContextValue,
  type ProductImagesTabStateContextValue,
} from './ProductImagesTabContext';

const FileManager = dynamic(() => import('@/features/files/public').then((mod) => mod.default), {
  ssr: false,
});

type ProductFormImagesContextValue = ReturnType<typeof useProductFormImages>;
type OnSelectFiles = NonNullable<ProductImagesTabActionsContextValue['onSelectFiles']>;

interface ProductImagesTabModel {
  chooseButtonAriaLabel: string;
  chooseButtonLabel: string;
  fastCometConfigError: string | null;
  clearFastCometConfigError: () => void;
  imageExternalBaseUrl: string | null;
  imageManagerController: ProductImageManagerController;
  inlineFileManager: boolean;
  onSelectFiles?: OnSelectFiles | undefined;
  onShowFileManager: (show: boolean) => void;
  productId: string | undefined;
  sectionDescription: string;
  sectionTitle: string;
  showFileManager: boolean;
}

type ProductImagesTabTextOptions = Pick<
  ProductImagesTabModel,
  'chooseButtonAriaLabel' | 'chooseButtonLabel' | 'sectionDescription' | 'sectionTitle'
>;
type FastCometUploadRuntimeCallbacks = Pick<
  ProductImageManagerController,
  'onFastCometUploadStart' | 'onFastCometUploadSuccess' | 'onFastCometUploadError'
>;

type FastCometUploadRuntimeState = FastCometUploadRuntimeCallbacks & {
  fastCometConfigError: string | null;
  clearFastCometConfigError: () => void;
};

const FASTCOMET_UPLOAD_RUNTIME_TTL_MS = 120_000;

const FASTCOMET_CONFIG_ERROR_PREFIXES = [
  'FastComet storage is not configured',
  'FastComet upload was rejected by the server',
] as const;

const isFastCometConfigError = (error: unknown): boolean =>
  error instanceof Error &&
  FASTCOMET_CONFIG_ERROR_PREFIXES.some((prefix) => error.message.startsWith(prefix));

const resolveFastCometUploadSource = (
  event: Pick<ProductImageManagerFastCometUploadEvent, 'imageFileId' | 'imageSlotIndex'>
): string | null =>
  buildQueuedProductFastCometUploadSource(event.imageFileId, event.imageSlotIndex);

const resolveFastCometUploadErrorMessage = (error: unknown): string => {
  if (error instanceof Error && error.message.trim().length > 0) return error.message;
  return 'FastComet upload failed.';
};

const resolveChooseButtonAriaLabel = (
  stateContext: ProductImagesTabStateContextValue | null
): string =>
  stateContext?.chooseButtonAriaLabel ?? 'Choose multiple existing images for the product';

const resolveChooseButtonLabel = (
  stateContext: ProductImagesTabStateContextValue | null
): string => stateContext?.chooseButtonLabel ?? 'Choose from File Manager';

const resolveSectionDescription = (
  stateContext: ProductImagesTabStateContextValue | null
): string =>
  stateContext?.sectionDescription ??
  'Upload directly from any slot (single or multi-select), or pick existing files from the platform library.';

const resolveSectionTitle = (stateContext: ProductImagesTabStateContextValue | null): string =>
  stateContext?.sectionTitle ?? 'Image Source';

const resolveTextOptions = (
  stateContext: ProductImagesTabStateContextValue | null
): ProductImagesTabTextOptions => ({
  chooseButtonAriaLabel: resolveChooseButtonAriaLabel(stateContext),
  chooseButtonLabel: resolveChooseButtonLabel(stateContext),
  sectionDescription: resolveSectionDescription(stateContext),
  sectionTitle: resolveSectionTitle(stateContext),
});

const resolveImageManagerController = (
  stateContext: ProductImagesTabStateContextValue | null,
  fallbackImageManagerController: ProductImageManagerController
): ProductImageManagerController =>
  stateContext?.imageManagerController ?? fallbackImageManagerController;

const resolveInlineFileManager = (
  stateContext: ProductImagesTabStateContextValue | null
): boolean => stateContext?.inlineFileManager ?? false;

const resolveOnSelectFiles = (
  actionsContext: ProductImagesTabActionsContextValue | null
): OnSelectFiles | undefined => actionsContext?.onSelectFiles;

const resolveOnShowFileManager = (
  actionsContext: ProductImagesTabActionsContextValue | null,
  formImages: ProductFormImagesContextValue
): ((show: boolean) => void) => actionsContext?.onShowFileManager ?? formImages.setShowFileManager;

const resolveShowFileManager = (
  stateContext: ProductImagesTabStateContextValue | null,
  formImages: ProductFormImagesContextValue
): boolean => stateContext?.showFileManager ?? formImages.showFileManager;

const useFastCometUploadRuntimeCallbacks = (): FastCometUploadRuntimeState => {
  const { toast } = useToast();
  const [fastCometConfigError, setFastCometConfigError] = useState<string | null>(null);

  const clearFastCometConfigError = useCallback(() => setFastCometConfigError(null), []);

  const onFastCometUploadStart = useCallback(
    (event: ProductImageManagerFastCometUploadEvent): void => {
      const source = resolveFastCometUploadSource(event);
      if (source !== null) {
        markQueuedProductSource(event.productId, source, FASTCOMET_UPLOAD_RUNTIME_TTL_MS);
      }
      toast('FastComet upload started.', { duration: 3000, variant: 'info' });
    },
    [toast]
  );

  const onFastCometUploadSuccess = useCallback(
    (event: ProductImageManagerFastCometUploadSuccessEvent): void => {
      const source = resolveFastCometUploadSource(event);
      if (source !== null) removeQueuedProductSource(event.productId, source);
      toast(
        event.alreadyUploaded === true
          ? 'Image is already on FastComet.'
          : 'Image uploaded to FastComet.',
        { variant: 'success' }
      );
    },
    [toast]
  );

  const onFastCometUploadError = useCallback(
    (event: ProductImageManagerFastCometUploadErrorEvent): void => {
      const source = resolveFastCometUploadSource(event);
      if (source !== null) removeQueuedProductSource(event.productId, source);
      if (isFastCometConfigError(event.error)) {
        setFastCometConfigError(resolveFastCometUploadErrorMessage(event.error));
        return;
      }
      toast(resolveFastCometUploadErrorMessage(event.error), {
        error: event.error,
        variant: 'error',
      });
    },
    [toast]
  );

  return useMemo(
    () => ({
      onFastCometUploadStart,
      onFastCometUploadSuccess,
      onFastCometUploadError,
      fastCometConfigError,
      clearFastCometConfigError,
    }),
    [onFastCometUploadStart, onFastCometUploadSuccess, onFastCometUploadError, fastCometConfigError, clearFastCometConfigError]
  );
};

type FallbackControllerResult = {
  controller: ProductImageManagerController;
  fastCometConfigError: string | null;
  clearFastCometConfigError: () => void;
};

type ControllerOnlyOptions = Omit<
  ProductImagesTabModel,
  keyof ProductImagesTabTextOptions | 'fastCometConfigError' | 'clearFastCometConfigError'
>;

const resolveControllerOptions = ({
  actionsContext,
  fallbackImageManagerController,
  formImages,
  imageExternalBaseUrl,
  stateContext,
}: {
  actionsContext: ProductImagesTabActionsContextValue | null;
  fallbackImageManagerController: ProductImageManagerController;
  formImages: ProductFormImagesContextValue;
  imageExternalBaseUrl: string | null;
  stateContext: ProductImagesTabStateContextValue | null;
}): ControllerOnlyOptions => ({
  imageExternalBaseUrl,
  imageManagerController: resolveImageManagerController(
    stateContext,
    fallbackImageManagerController
  ),
  inlineFileManager: resolveInlineFileManager(stateContext),
  onSelectFiles: resolveOnSelectFiles(actionsContext),
  onShowFileManager: resolveOnShowFileManager(actionsContext, formImages),
  productId: formImages.productId,
  showFileManager: resolveShowFileManager(stateContext, formImages),
});

const useFallbackImageManagerController = (
  formImages: ProductFormImagesContextValue
): FallbackControllerResult => {
  const {
    fastCometConfigError,
    clearFastCometConfigError,
    ...callbacks
  } = useFastCometUploadRuntimeCallbacks();

  const controller = useMemo<ProductImageManagerController>(
    () => ({
      imageSlots: formImages.imageSlots,
      imageLinks: formImages.imageLinks,
      imageBase64s: formImages.imageBase64s,
      setImageLinkAt: formImages.setImageLinkAt,
      setImageBase64At: formImages.setImageBase64At,
      handleSlotImageChange: formImages.handleSlotImageChange,
      handleSlotFileSelect: formImages.handleSlotFileSelect,
      handleSlotDisconnectImage: formImages.handleSlotDisconnectImage,
      setShowFileManager: formImages.setShowFileManager,
      setShowFileManagerForSlot: () => formImages.setShowFileManager(true),
      swapImageSlots: formImages.swapImageSlots,
      setImagesReordering: formImages.setImagesReordering,
      uploadError: formImages.uploadError,
      ...callbacks,
    }),
    [
      formImages.imageSlots,
      formImages.imageLinks,
      formImages.imageBase64s,
      formImages.setImageLinkAt,
      formImages.setImageBase64At,
      formImages.handleSlotImageChange,
      formImages.handleSlotFileSelect,
      formImages.handleSlotDisconnectImage,
      formImages.setShowFileManager,
      formImages.swapImageSlots,
      formImages.setImagesReordering,
      formImages.uploadError,
      callbacks,
    ]
  );

  return useMemo(
    () => ({ controller, fastCometConfigError, clearFastCometConfigError }),
    [controller, fastCometConfigError, clearFastCometConfigError]
  );
};

function useProductImagesTabModel(): ProductImagesTabModel {
  const formImages = useProductFormImages();
  const { imageExternalBaseUrl } = useProductSettings();
  const imagesTabStateContext = useOptionalProductImagesTabStateContext();
  const imagesTabActionsContext = useOptionalProductImagesTabActionsContext();
  const {
    controller: fallbackImageManagerController,
    fastCometConfigError,
    clearFastCometConfigError,
  } = useFallbackImageManagerController(formImages);

  return {
    ...resolveTextOptions(imagesTabStateContext),
    fastCometConfigError,
    clearFastCometConfigError,
    ...resolveControllerOptions({
      actionsContext: imagesTabActionsContext,
      fallbackImageManagerController,
      formImages,
      imageExternalBaseUrl,
      stateContext: imagesTabStateContext,
    }),
  };
}

function InlineFileManagerView({
  onSelectFiles,
  onShowFileManager,
}: {
  onSelectFiles: (files: ImageFileSelection[]) => void;
  onShowFileManager: (show: boolean) => void;
}): React.JSX.Element {
  return (
    <div className='space-y-4'>
      <div className='flex justify-end'>
        <Button type='button' variant='outline' onClick={(): void => onShowFileManager(false)}>
          Back to Images
        </Button>
      </div>
      <FileManager onSelectFile={onSelectFiles} />
    </div>
  );
}

function ImageSourceSection({
  model,
}: {
  model: ProductImagesTabModel;
}): React.JSX.Element {
  return (
    <FormSection title={model.sectionTitle} description={model.sectionDescription}>
      <div className='flex space-x-4'>
        <Button
          type='button'
          variant='outline'
          onClick={(): void => model.onShowFileManager(true)}
          aria-label={model.chooseButtonAriaLabel}
        >
          {model.chooseButtonLabel}
        </Button>
      </div>
    </FormSection>
  );
}

function ProductImagesDefaultView({ model }: { model: ProductImagesTabModel }): React.JSX.Element {
  return (
    <div className='space-y-6'>
      {model.fastCometConfigError !== null && (
        <Alert variant='warning' onDismiss={model.clearFastCometConfigError}>
          {model.fastCometConfigError}{' '}
          <Link href='/admin/settings/storage' className='font-medium underline'>
            Go to Storage Settings
          </Link>
        </Alert>
      )}
      <ImageSourceSection model={model} />
      <ProductImageManagerControllerProvider value={model.imageManagerController}>
        <ProductImageManager
          externalBaseUrl={model.imageExternalBaseUrl}
          productId={model.productId}
        />
      </ProductImageManagerControllerProvider>
    </div>
  );
}

export function ProductImagesTabContent(): React.JSX.Element {
  const model = useProductImagesTabModel();

  if (
    model.inlineFileManager === true &&
    model.showFileManager === true &&
    model.onSelectFiles !== undefined
  ) {
    return (
      <InlineFileManagerView
        onSelectFiles={model.onSelectFiles}
        onShowFileManager={model.onShowFileManager}
      />
    );
  }

  return <ProductImagesDefaultView model={model} />;
}

'use client';

import React, { useCallback, useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import dynamic from 'next/dynamic';

import { useExportProductToEcommerce } from '@/features/products/hooks/useProductEcommerceExportMutations';
import type { ProductWithImages } from '@/shared/contracts/products/product';
import { invalidateListingBadges } from '@/shared/lib/query-invalidation';
import { Button } from '@/shared/ui/button';
import { useToast } from '@/shared/ui/toast';
import { logClientError } from '@/shared/utils/observability/client-error-logger';
import { cn } from '@/shared/utils/ui-utils';

const EcommerceManageModal = dynamic(
  () => import('./EcommerceManageModal').then((mod) => mod.EcommerceManageModal),
  { ssr: false }
);

type EcommerceExportButtonProps = {
  product: ProductWithImages;
  showEcommerceBadge?: boolean;
  ecommerceStatus?: string;
};

const resolveSuccessMessage = (status: string): string => {
  if (status === 'created') return 'Product exported to ecommerce.';
  if (status === 'updated') return 'Ecommerce product updated.';
  return 'Ecommerce product is already up to date.';
};

export function EcommerceExportButton({
  product,
  showEcommerceBadge = false,
  ecommerceStatus,
}: EcommerceExportButtonProps): React.JSX.Element {
  const { mutateAsync, isPending } = useExportProductToEcommerce();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [modalOpen, setModalOpen] = useState(false);

  const isActive = showEcommerceBadge && ecommerceStatus === 'active';

  const handleClick = useCallback((): void => {
    if (isPending) return;
    if (isActive) {
      setModalOpen(true);
      return;
    }
    void mutateAsync(product.id)
      .then((response) => {
        toast(resolveSuccessMessage(response.status), { variant: 'success' });
        invalidateListingBadges(queryClient);
      })
      .catch((error: unknown) => {
        logClientError(error);
        toast(
          error instanceof Error ? error.message : 'Failed to export product to ecommerce.',
          { variant: 'error' }
        );
      });
  }, [isPending, isActive, mutateAsync, product.id, queryClient, toast]);

  const ariaLabel = isActive ? 'Manage ecommerce product' : 'Export to ecommerce';

  return (
    <>
      <Button
        type='button'
        disabled={isPending}
        onClick={handleClick}
        variant='ghost'
        size='icon'
        aria-label={ariaLabel}
        title={ariaLabel}
        className={cn(
          'size-8 rounded-full border p-0',
          isActive
            ? 'border-emerald-400/70 bg-emerald-500/15 text-emerald-100 hover:border-emerald-300/80 hover:bg-emerald-500/25'
            : 'border-gray-500/60 bg-gray-500/10 text-gray-400 hover:border-gray-400/70 hover:bg-gray-500/20 hover:text-gray-300',
          isPending && 'cursor-not-allowed opacity-60'
        )}
      >
        <span
          aria-hidden='true'
          className='text-[9px] font-black uppercase leading-none tracking-tight'
        >
          {isPending ? '...' : 'EC'}
        </span>
      </Button>
      {modalOpen && (
        <EcommerceManageModal
          product={product}
          open={modalOpen}
          onClose={(): void => setModalOpen(false)}
        />
      )}
    </>
  );
}

'use client';

import React, { useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';

import type { ProductWithImages } from '@/shared/contracts/products/product';
import { invalidateListingBadges } from '@/shared/lib/query-invalidation';
import { Button } from '@/shared/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/shared/ui/dialog';
import { useToast } from '@/shared/ui/toast';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

import {
  useDeleteProductFromEcommerce,
  useExportProductToEcommerce,
} from '@/features/products/hooks/useProductEcommerceExportMutations';

type EcommerceManageModalProps = {
  product: ProductWithImages;
  open: boolean;
  onClose: () => void;
};

export function EcommerceManageModal({
  product,
  open,
  onClose,
}: EcommerceManageModalProps): React.JSX.Element {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const exportMutation = useExportProductToEcommerce();
  const deleteMutation = useDeleteProductFromEcommerce();

  const isPending = exportMutation.isPending || deleteMutation.isPending;

  const handleSync = useCallback((): void => {
    if (isPending) return;
    void exportMutation.mutateAsync(product.id)
      .then(() => {
        toast('Ecommerce product synced successfully.', { variant: 'success' });
        invalidateListingBadges(queryClient);
        onClose();
      })
      .catch((error: unknown) => {
        logClientError(error);
        toast(
          error instanceof Error ? error.message : 'Failed to sync product to ecommerce.',
          { variant: 'error' }
        );
      });
  }, [exportMutation, isPending, onClose, product.id, queryClient, toast]);

  const handleDelete = useCallback((): void => {
    if (isPending) return;
    void deleteMutation.mutateAsync(product.id)
      .then(() => {
        toast('Product removed from ecommerce store.', { variant: 'success' });
        invalidateListingBadges(queryClient);
        onClose();
      })
      .catch((error: unknown) => {
        logClientError(error);
        toast(
          error instanceof Error ? error.message : 'Failed to remove product from ecommerce.',
          { variant: 'error' }
        );
      });
  }, [deleteMutation, isPending, onClose, product.id, queryClient, toast]);

  const productName =
    product.name_en ?? product.name_pl ?? product.name_de ?? product.sku ?? product.id;

  return (
    <Dialog open={open} onOpenChange={(isOpen): void => { if (!isOpen) onClose(); }}>
      <DialogContent className='max-w-sm'>
        <DialogHeader>
          <DialogTitle className='text-base'>Ecommerce Store</DialogTitle>
        </DialogHeader>
        <p className='text-sm text-muted-foreground truncate' title={productName ?? undefined}>
          {productName}
        </p>
        <DialogFooter className='flex-col gap-2 sm:flex-col'>
          <Button
            type='button'
            onClick={handleSync}
            disabled={isPending}
            className='w-full bg-emerald-600 hover:bg-emerald-700 text-white'
          >
            {exportMutation.isPending ? 'Syncing…' : 'Sync to ecommerce'}
          </Button>
          <Button
            type='button'
            variant='destructive'
            onClick={handleDelete}
            disabled={isPending}
            className='w-full'
          >
            {deleteMutation.isPending ? 'Removing…' : 'Remove from ecommerce'}
          </Button>
          <Button
            type='button'
            variant='ghost'
            onClick={onClose}
            disabled={isPending}
            className='w-full'
          >
            Cancel
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

'use client';

// ProductListContext: central composition root for product list UI state.
// - Composes many small contexts (filters, selection, table, actions, alerts,
//   modals, row visuals, row runtime store) into a single Provider to avoid
//   deep prop-drilling and to keep render boundaries explicit.
// - Uses a global registry when creating contexts to preserve context
//   identity across hot-reloads and bundler/loader boundaries (prevents
//   "must be used within a Provider" errors when modules are re-evaluated).
// - The row runtime store is a lightweight, external store created once per
//   provider instance; consumers use useSyncExternalStore (via
//   useProductListRowRuntime) to subscribe to fine-grained per-row snapshots
//   without forcing whole-list re-renders.

import React, { useEffect, useMemo, useRef, useSyncExternalStore } from 'react';

import {
  useDefaultTraderaConnection,
  useIntegrationListingBadges,
} from '@/features/integrations/product-integrations-adapter';
import { internalError } from '@/shared/errors/app-error';
import { createStrictContext } from '@/shared/lib/react/createStrictContext';

import { useProductListListingStatuses } from '../hooks/product-list/useProductListListingStatuses';

import { useProductListSubContexts } from './hooks/useProductListSubContexts';
import {
  createProductListRowRuntimeStore,
  EMPTY_PRODUCT_LIST_ROW_RUNTIME_SNAPSHOT,
  type ProductListRowRuntimeStoreState,
  type ProductListRowRuntimeStore,
} from './hooks/useProductListRowRuntimeStore';
import type {
  ProductListActionsContextType,
  ProductListAlertsContextType,
  ProductListContextType,
  ProductListFiltersContextType,
  ProductListHeaderActionsContextType,
  ProductListModalsContextType,
  ProductListRowActionsContextType,
  ProductListRowRuntimeContextType,
  ProductListRowVisualsContextType,
  ProductListSelectionContextType,
  ProductListTableContextType,
} from './ProductListContext.types';

export type {
  ProductListActionsContextType,
  ProductListAlertsContextType,
  ProductListContextType,
  ProductListFiltersContextType,
  ProductListHeaderActionsContextType,
  ProductListModalsContextType,
  ProductListRowActionsContextType,
  ProductListRowRuntimeContextType,
  ProductListRowVisualsContextType,
  ProductListSelectionContextType,
  ProductListTableContextType,
} from './ProductListContext.types';

type ProductListProviderValue = ProductListContextType & {
  rowRuntimeReady?: boolean;
  triggerListingStatusHighlight?: (productId: string) => void;
};

type ProductListProviderProps = {
  value: ProductListProviderValue;
  children: React.ReactNode;
};

type ProductListSubContexts = ReturnType<typeof useProductListSubContexts>;

const createProductListStrictContext = <T,>(
  hookName: string,
  displayName: string
): ReturnType<typeof createStrictContext<T>> => {
  // Use a global registry to ensure that even if this module is executed multiple times
  // (e.g., due to dynamic imports in some bundlers like Turbopack), the context objects
  // remain stable. This prevents \"must be used within a Provider\" errors caused by
  // context object identity mismatches.
  const registryKey = `__PRODUCT_LIST_CONTEXT_${hookName}`;
  const globalObj = globalThis as unknown as Record<string, unknown>;
  const existingContext = globalObj[registryKey];

  if (existingContext !== undefined) {
    return existingContext as ReturnType<typeof createStrictContext<T>>;
  }

  const result = createStrictContext<T>({
    hookName,
    providerName: 'a ProductListProvider',
    displayName,
    errorFactory: internalError,
  });

  globalObj[registryKey] = result;
  return result;
};

export const {
  Context: ProductListFiltersContext,
  useStrictContext: useProductListFiltersContext,
} = createProductListStrictContext<ProductListFiltersContextType>(
  'useProductListFiltersContext',
  'ProductListFiltersContext'
);

